import React, { useState, useEffect, useRef } from 'react';
import {
  ShoppingBag, ShoppingCart, LogOut, User, MapPin, Package,
  Plus, Trash2, ArrowRight, Edit3, Check, X,
  ChevronRight, TrendingUp, Zap, Home, Briefcase, Star, Pencil
} from 'lucide-react';
import { authAPI, addressAPI } from '../api';

// ─── Design token ──────────────────────────────────────────────────
const PRI = 'bg-gradient-to-r from-teal-500 to-cyan-600 hover:from-teal-600 hover:to-cyan-700 text-white font-semibold transition-all shadow-md hover:shadow-cyan-200/50 active:scale-95';

// ─── Shared input class helper ─────────────────────────────────────
const inputCls = (err) =>
  `w-full px-4 py-3 rounded-2xl text-sm font-medium transition-all focus:outline-none focus:ring-4 placeholder-slate-300 ${
    err
      ? 'border-2 border-red-300 bg-red-50 focus:border-red-400 focus:ring-red-50'
      : 'border-2 border-gray-100 bg-white focus:border-teal-400 focus:ring-teal-50 hover:border-gray-200'
  }`;

// ─── Address Modal (Add + Edit) ────────────────────────────────────
// mode: 'add' | 'edit'
// existingAddress: populated when mode === 'edit'
const AddressModal = ({ mode = 'add', existingAddress = null, onClose, onSave, saving }) => {
  const blankForm = {
    label: 'Home', addressLine1: '', addressLine2: '',
    city: '', state: '', postalCode: '', country: 'India', isDefault: false
  };

  // Pre-populate form when editing
  const [form, setForm] = useState(() => {
    if (mode === 'edit' && existingAddress) {
      return {
        label:        existingAddress.label        || 'Home',
        addressLine1: existingAddress.AddressLine1 || existingAddress.addressLine1 || '',
        addressLine2: existingAddress.AddressLine2 || existingAddress.addressLine2 || '',
        city:         existingAddress.City         || existingAddress.city         || '',
        state:        existingAddress.State        || existingAddress.state        || '',
        postalCode:   existingAddress.PostalCode   || existingAddress.postalCode   || '',
        country:      existingAddress.Country      || existingAddress.country      || 'India',
        isDefault:    !!(existingAddress.IsDefault || existingAddress.isDefault),
      };
    }
    return blankForm;
  });

  const [errors, setErrors] = useState({});
  const firstRef = useRef(null);

  useEffect(() => {
    // Small delay so the modal spring animation finishes before focusing
    const t = setTimeout(() => firstRef.current?.focus(), 120);
    document.body.style.overflow = 'hidden';
    return () => { clearTimeout(t); document.body.style.overflow = ''; };
  }, []);

  const set = (k, v) => {
    setForm(p => ({ ...p, [k]: v }));
    setErrors(p => ({ ...p, [k]: '' }));
  };

  const validate = () => {
    const e = {};
    if (!form.addressLine1.trim()) e.addressLine1 = 'Address line 1 is required';
    if (!form.city.trim())         e.city         = 'City is required';
    if (!form.postalCode.trim())   e.postalCode   = 'Postal code is required';
    setErrors(e);
    return Object.keys(e).length === 0;
  };

  const handleSubmit = () => { if (validate()) onSave(form); };

  const labelOptions = [
    { value: 'Home',  icon: Home,      activeCls: 'bg-teal-50   border-teal-300   text-teal-700'   },
    { value: 'Work',  icon: Briefcase, activeCls: 'bg-violet-50 border-violet-300 text-violet-700' },
    { value: 'Other', icon: MapPin,    activeCls: 'bg-orange-50 border-orange-300 text-orange-700' },
  ];

  const isEdit = mode === 'edit';

  return (
    <div
      className="fixed inset-0 z-[100] flex items-center justify-center p-4"
      style={{ background: 'rgba(15,23,42,0.5)', backdropFilter: 'blur(6px)', animation: 'modalBg .2s ease both' }}
      onClick={e => e.target === e.currentTarget && onClose()}
    >
      <div
        className="w-full max-w-lg bg-white rounded-[32px] overflow-hidden shadow-2xl"
        style={{ animation: 'modalSlide .35s cubic-bezier(0.34,1.56,0.64,1) both', maxHeight: '92vh' }}
      >
        <style>{`
          @keyframes modalBg{from{opacity:0}to{opacity:1}}
          @keyframes modalSlide{from{opacity:0;transform:scale(.92) translateY(24px)}to{opacity:1;transform:scale(1) translateY(0)}}
        `}</style>

        {/* ── Header ── */}
        <div className="relative px-7 py-5 bg-gradient-to-r from-teal-500 to-cyan-600 overflow-hidden shrink-0">
          {/* grid texture */}
          <div className="absolute inset-0 opacity-10"
            style={{ backgroundImage: 'linear-gradient(rgba(255,255,255,.5) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.5) 1px,transparent 1px)', backgroundSize: '32px 32px' }} />
          {/* glow orb */}
          <div className="absolute right-0 top-0 w-44 h-44 rounded-full opacity-20"
            style={{ background: 'white', filter: 'blur(36px)', transform: 'translate(30%,-30%)' }} />

          <div className="relative z-10 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="w-11 h-11 rounded-2xl flex items-center justify-center"
                style={{ background: 'rgba(255,255,255,0.22)', border: '1px solid rgba(255,255,255,0.3)' }}>
                {isEdit ? <Pencil className="w-5 h-5 text-white" /> : <MapPin className="w-5 h-5 text-white" />}
              </div>
              <div>
                <h3 className="text-white font-black text-lg leading-none">
                  {isEdit ? 'Edit Address' : 'Add New Address'}
                </h3>
                <p className="text-teal-100 text-xs mt-0.5">
                  {isEdit ? 'Update your saved address' : 'Save for faster checkout'}
                </p>
              </div>
            </div>
            <button onClick={onClose}
              className="w-9 h-9 flex items-center justify-center rounded-xl text-white/70 hover:text-white hover:bg-white/15 transition-all">
              <X className="w-5 h-5" />
            </button>
          </div>
        </div>

        {/* ── Scrollable body ── */}
        <div className="overflow-y-auto px-7 py-6 space-y-5"
          style={{ maxHeight: 'calc(92vh - 160px)', scrollbarWidth: 'thin', scrollbarColor: 'rgba(20,184,166,0.2) transparent' }}>

          {/* Address type picker */}
          <div>
            <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-2.5">Address Type</label>
            <div className="flex gap-2">
              {labelOptions.map(opt => {
                const Icon = opt.icon;
                const active = form.label === opt.value;
                return (
                  <button key={opt.value} type="button" onClick={() => set('label', opt.value)}
                    className={`flex-1 flex items-center justify-center gap-1.5 py-2.5 rounded-2xl text-sm font-bold border-2 transition-all active:scale-95 ${
                      active ? `${opt.activeCls} shadow-sm scale-[1.02]` : 'bg-white border-gray-100 text-slate-500 hover:border-gray-200'
                    }`}>
                    <Icon className="w-4 h-4" />
                    {opt.value}
                    {active && <Check className="w-3.5 h-3.5" />}
                  </button>
                );
              })}
            </div>
          </div>

          {/* Fields */}
          <div className="grid grid-cols-2 gap-4">

            {/* Address Line 1 — full width */}
            <div className="col-span-2">
              <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5">
                Address Line 1 <span className="text-red-400">*</span>
              </label>
              <input ref={firstRef}
                value={form.addressLine1}
                onChange={e => set('addressLine1', e.target.value)}
                placeholder="House / Flat no., Building name, Street"
                className={inputCls(errors.addressLine1)}
              />
              {errors.addressLine1 && <p className="text-[11px] text-red-500 font-semibold mt-1 ml-1">⚠ {errors.addressLine1}</p>}
            </div>

            {/* Address Line 2 — full width */}
            <div className="col-span-2">
              <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5">
                Address Line 2 &nbsp;<span className="text-slate-300 font-medium normal-case">(optional)</span>
              </label>
              <input value={form.addressLine2} onChange={e => set('addressLine2', e.target.value)}
                placeholder="Landmark, Area, Colony"
                className={inputCls(false)} />
            </div>

            {/* City */}
            <div>
              <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5">
                City <span className="text-red-400">*</span>
              </label>
              <input value={form.city} onChange={e => set('city', e.target.value)}
                placeholder="e.g. Mumbai"
                className={inputCls(errors.city)} />
              {errors.city && <p className="text-[11px] text-red-500 font-semibold mt-1 ml-1">⚠ {errors.city}</p>}
            </div>

            {/* State */}
            <div>
              <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5">State</label>
              <input value={form.state} onChange={e => set('state', e.target.value)}
                placeholder="e.g. Maharashtra"
                className={inputCls(false)} />
            </div>

            {/* Postal Code */}
            <div>
              <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5">
                Postal Code <span className="text-red-400">*</span>
              </label>
              <input value={form.postalCode} onChange={e => set('postalCode', e.target.value)}
                placeholder="e.g. 400001" maxLength={10}
                className={inputCls(errors.postalCode)} />
              {errors.postalCode && <p className="text-[11px] text-red-500 font-semibold mt-1 ml-1">⚠ {errors.postalCode}</p>}
            </div>

            {/* Country */}
            <div>
              <label className="block text-xs font-black text-slate-500 uppercase tracking-widest mb-1.5">Country</label>
              <select value={form.country} onChange={e => set('country', e.target.value)}
                className="w-full px-4 py-3 rounded-2xl text-sm font-medium border-2 border-gray-100 bg-white focus:border-teal-400 focus:ring-4 focus:ring-teal-50 focus:outline-none hover:border-gray-200 transition-all text-slate-800">
                {['India','United States','United Kingdom','Canada','Australia','Singapore','UAE','Other'].map(c => (
                  <option key={c} value={c}>{c}</option>
                ))}
              </select>
            </div>
          </div>

          {/* Default toggle */}
          <button type="button" onClick={() => set('isDefault', !form.isDefault)}
            className={`w-full flex items-center justify-between px-5 py-4 rounded-2xl border-2 transition-all ${
              form.isDefault ? 'border-teal-300 bg-teal-50' : 'border-gray-100 bg-white hover:border-gray-200'
            }`}>
            <div className="flex items-center gap-3">
              <div className={`w-10 h-10 rounded-xl flex items-center justify-center transition-all ${form.isDefault ? 'bg-gradient-to-br from-teal-500 to-cyan-600' : 'bg-slate-100'}`}>
                <Star className={`w-4 h-4 ${form.isDefault ? 'text-white fill-white' : 'text-slate-400'}`} />
              </div>
              <div className="text-left">
                <p className={`text-sm font-bold ${form.isDefault ? 'text-teal-700' : 'text-slate-700'}`}>
                  Set as Default Address
                </p>
                <p className="text-xs text-slate-400">Used automatically at checkout</p>
              </div>
            </div>
            {/* Animated toggle pill */}
            <div className={`w-12 h-6 rounded-full transition-all duration-300 relative shrink-0 ${form.isDefault ? 'bg-gradient-to-r from-teal-500 to-cyan-600' : 'bg-gray-200'}`}>
              <div className={`absolute top-0.5 w-5 h-5 bg-white rounded-full shadow-md transition-all duration-300 ${form.isDefault ? 'left-6' : 'left-0.5'}`} />
            </div>
          </button>
        </div>

        {/* ── Footer ── */}
        <div className="px-7 py-4 bg-slate-50 border-t border-gray-100 flex gap-3 shrink-0">
          <button onClick={onClose}
            className="flex-1 py-3 rounded-2xl text-sm font-bold text-slate-600 bg-white border-2 border-gray-100 hover:border-gray-200 hover:bg-gray-50 active:scale-95 transition-all">
            Cancel
          </button>
          <button onClick={handleSubmit} disabled={saving}
            className={`flex-1 py-3 rounded-2xl text-sm font-black flex items-center justify-center gap-2 ${PRI} disabled:opacity-60 disabled:cursor-not-allowed`}>
            {saving
              ? <><div className="w-4 h-4 border-2 border-white border-t-transparent rounded-full animate-spin" />Saving...</>
              : <><Check className="w-4 h-4" />{isEdit ? 'Update Address' : 'Save Address'}</>
            }
          </button>
        </div>
      </div>
    </div>
  );
};

