// ProfilePage
// ══════════════════════════════════════════════════════════════════
const ProfilePage = ({
  user, cart, orders, profileData, setProfileData,
  setCurrentPage, handleLogout, setError, loadOrders, loading, setLoading
}) => {
  const [editMode,          setEditMode]          = useState(false);
  const [activeTab,         setActiveTab]          = useState('profile');
  const [savingProfile,     setSavingProfile]      = useState(false);
  // Address modal state
  const [addressModal,      setAddressModal]       = useState(null);
  // null | { mode:'add' } | { mode:'edit', address: {...} }
  const [savingAddress,     setSavingAddress]      = useState(false);
  const [toast,             setToast]              = useState(null); // { type:'success'|'error', msg }

  useEffect(() => { fetchAddresses(); fetchProfile(); }, []);
  useEffect(() => { if (user) fetchOrders(); }, [user]);

  // ── Fetch profile ──────────────────────────────────────────────
  const fetchProfile = async () => {
    try {
      const res = await authAPI.getProfile();
      const d = res.data;
      setProfileData({
        fullName: d.fullName || user?.name  || '',
        email:    d.email    || user?.email || '',
        mobile:   d.mobile   || user?.mobile || '',
        gender:   d.gender   || user?.gender || '',
        addresses: d.addresses || [],
      });
    } catch {
      if (user) setProfileData({
        fullName: user.name  || '', email:  user.email  || '',
        mobile:   user.mobile || '', gender: user.gender || '', addresses: [],
      });
    }
  };

  // ── Fetch addresses ────────────────────────────────────────────
  // getAll() is JWT-protected — returns ONLY current user's addresses.
  // No userId filtering needed.
  const fetchAddresses = async () => {
    try {
      const res = await addressAPI.getAll();
      // res.data is the array (full axios response from getAll)
      const raw = Array.isArray(res.data)
        ? res.data
        : (res.data?.addresses || res.data?.data || []);

      const normalized = raw.map((a, idx) => {
        const l1    = a.AddressLine1 || a.addressLine1 || a.line1   || '';
        const l2    = a.AddressLine2 || a.addressLine2 || a.line2   || '';
        const city  = a.City   || a.city   || '';
        const state = a.State  || a.state  || '';
        const postal= a.PostalCode || a.postalCode || a.pincode || '';
        const cntry = a.Country || a.country || '';
        // Handle MongoDB ObjectId formats: string, { $oid: "..." }, or object
        const rawId = a.Id || a.id || a._id;
        const id    = (rawId && typeof rawId === 'object' && rawId.$oid)
          ? rawId.$oid
          : (typeof rawId === 'string' ? rawId : `addr_${Date.now()}_${idx}`);
        return {
          id,
          label:        a.Label || a.label || ((a.IsDefault || a.isDefault) ? 'Home' : 'Address'),
          AddressLine1: l1, AddressLine2: l2,
          City: city, State: state, PostalCode: postal, Country: cntry,
          IsDefault: !!(a.IsDefault || a.isDefault),
          address: [l1, l2, city, state, postal, cntry].filter(Boolean).join(', '),
        };
      });

      setProfileData(prev => ({ ...prev, addresses: normalized }));
    } catch (err) {
      console.error('fetchAddresses error:', err?.response?.data || err.message);
      setProfileData(prev => ({ ...prev, addresses: [] }));
    }
  };

  const handleSaveProfile = async () => {
    try {
      setSavingProfile(true); setError('');
      if (typeof authAPI.updateProfile === 'function') {
        await authAPI.updateProfile({
          fullName: profileData.fullName,
          mobile:   profileData.mobile,
          gender:   profileData.gender,
        });
      }
      const u = JSON.parse(sessionStorage.getItem('user') || '{}');
      sessionStorage.setItem('user', JSON.stringify({
        ...u,
        fullName: profileData.fullName,
        mobile:   profileData.mobile,
        gender:   profileData.gender,
      }));
      setEditMode(false);
    } catch (err) {
      setError(err.response?.data?.message || err.message || 'Failed to update profile.');
    } finally {
      setSavingProfile(false);
    }
  };

  const fetchOrders = async () => { try { await loadOrders(); } catch {} };

  // ── Toast helper (defined first so handleSaveAddress can call it) ──
  const showToast = (type, msg) => {
    setToast({ type, msg });
    setTimeout(() => setToast(null), 3500);
  };

  // ── Save address (Add or Edit) ─────────────────────────────────
  // addressAPI.add()   → POST /MongoAddress  (backend reads userId from JWT — no userId in body)
  // addressAPI.update() → PUT  /MongoAddress/{id}
  // IMPORTANT: never send userId in the payload — the .NET backend reads it from the Bearer token
  const handleSaveAddress = async (form) => {
    try {
      setSavingAddress(true);

      // Payload: camelCase keys only, NO userId
      const payload = {
        label:        form.label        || 'Home',
        addressLine1: (form.addressLine1 || '').trim(),
        addressLine2: (form.addressLine2 || '').trim(),
        city:         (form.city        || '').trim(),
        state:        (form.state       || '').trim(),
        postalCode:   (form.postalCode  || '').trim(),
        country:      form.country      || 'India',
        isDefault:    !!form.isDefault,
      };

      console.log('💾 Saving address payload:', payload);
      console.log('📋 Modal mode:', addressModal?.mode, '| address id:', addressModal?.address?.id);

      if (addressModal?.mode === 'edit' && addressModal?.address?.id) {
        await addressAPI.update(addressModal.address.id, payload);
      } else {
        await addressAPI.add(payload);
      }

      // Refresh the list from server so we see the saved data
      await fetchAddresses();
      setAddressModal(null);
      showToast('success', addressModal?.mode === 'edit' ? 'Address updated!' : 'Address saved!');
    } catch (err) {
      console.error('❌ Save address error:', err?.response?.status, err?.response?.data || err.message);
      const msg = err?.response?.data?.message
        || err?.response?.data?.title
        || err?.response?.data
        || err.message
        || 'Failed to save address.';
      showToast('error', typeof msg === 'string' ? msg : JSON.stringify(msg));
    } finally {
      setSavingAddress(false);
    }
  };

  // ── Remove address ─────────────────────────────────────────────
  const removeAddress = async (id) => {
    try {
      await addressAPI.remove(id);
      await fetchAddresses();
    } catch {
      setError('Failed to delete address. Please try again.');
    }
  };

  // ── UI helpers ─────────────────────────────────────────────────
  const tabs = [
    { id: 'profile',   label: 'Profile',   icon: User    },
    { id: 'addresses', label: 'Addresses', icon: MapPin  },
    { id: 'orders',    label: 'Orders',    icon: Package },
  ];

  const displayName = profileData.fullName || user?.fullName || user?.name || 'User';
  const initials    = displayName.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase();
  const totalSpent  = orders.reduce((s, o) => s + (o.totalAmount || 0), 0);

  // Label → icon/color mapping for address cards
  const labelMeta = {
    Home:  { Icon: Home,      bg: 'from-teal-500 to-cyan-600'     },
    Work:  { Icon: Briefcase, bg: 'from-violet-500 to-purple-600' },
    Other: { Icon: MapPin,    bg: 'from-orange-400 to-rose-500'   },
  };

  return (
    <div className="min-h-screen bg-[#F8FAFC] font-sans selection:bg-teal-100 selection:text-teal-900">
      <link href="https://fonts.googleapis.com/css2?family=Outfit:wght@400;500;600;700;800;900&display=swap" rel="stylesheet" />
      <style>{`
        body { font-family: 'Outfit', sans-serif; }
        @keyframes fadeIn { from { opacity:0; transform:translateY(10px); } to { opacity:1; transform:translateY(0); } }
        @keyframes toastIn { from { opacity:0; transform:translateY(20px) scale(.95); } to { opacity:1; transform:translateY(0) scale(1); } }
      `}</style>

      {/* ── NAV ─────────────────────────────────────────────────── */}
      <nav className="sticky top-0 z-50 bg-white/80 backdrop-blur-md border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-2.5 group cursor-pointer" onClick={() => setCurrentPage('products')}>
            <div className="bg-gradient-to-br from-teal-500 to-cyan-600 p-2 rounded-xl group-hover:rotate-12 transition-transform duration-300">
              <ShoppingBag className="w-6 h-6 text-white" />
            </div>
            <span className="text-2xl font-black bg-clip-text text-transparent bg-gradient-to-r from-teal-600 to-cyan-700 tracking-tight">
              ShopAI
            </span>
          </div>

          <div className="hidden md:flex items-center gap-1">
            {[{ label: 'Shop', page: 'products' }, { label: 'Orders', page: 'orders' }].map(n => (
              <button key={n.page} onClick={() => setCurrentPage(n.page)}
                className="text-sm font-bold text-slate-500 hover:text-teal-600 hover:bg-teal-50 px-4 py-2 rounded-xl transition-all">
                {n.label}
              </button>
            ))}
          </div>

          <div className="flex items-center gap-3">
            <button onClick={() => setCurrentPage('cart')}
              className="relative p-2.5 text-slate-500 hover:text-teal-600 hover:bg-teal-50 rounded-xl transition-all">
              <ShoppingCart className="w-6 h-6" />
              {cart.length > 0 && (
                <span className="absolute -top-1 -right-1 w-5 h-5 bg-orange-500 text-white text-[10px] font-black rounded-full flex items-center justify-center">
                  {cart.length}
                </span>
              )}
            </button>
            <button onClick={handleLogout}
              className="hidden sm:flex items-center gap-2 text-sm font-bold text-slate-500 hover:text-red-500 hover:bg-red-50 px-3 py-2 rounded-xl transition-all">
              <LogOut className="w-4 h-4" /> Logout
            </button>
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-6 py-10">

        {/* ── Hero Profile Banner ──────────────────────────────── */}
        <div className="relative mb-8 rounded-[32px] overflow-hidden"
          style={{ background: 'linear-gradient(135deg, #14b8a6 0%, #0891b2 60%, #0284c7 100%)' }}>
          {/* grid texture */}
          <div className="absolute inset-0 opacity-[0.08]"
            style={{ backgroundImage: 'linear-gradient(rgba(255,255,255,.6) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.6) 1px,transparent 1px)', backgroundSize: '40px 40px' }} />
          {/* glow */}
          <div className="absolute right-0 top-0 w-96 h-96 rounded-full opacity-20"
            style={{ background: 'white', filter: 'blur(80px)', transform: 'translate(30%,-30%)' }} />

          <div className="relative z-10 px-8 py-8 flex flex-col md:flex-row items-start md:items-center gap-6">
            {/* Avatar */}
            <div className="relative shrink-0">
              <div className="w-24 h-24 rounded-3xl flex items-center justify-center text-3xl font-black text-white shadow-2xl"
                style={{ background: 'rgba(255,255,255,0.2)', border: '3px solid rgba(255,255,255,0.35)', backdropFilter: 'blur(10px)' }}>
                {initials}
              </div>
              <button onClick={() => setActiveTab('profile')}
                className="absolute -bottom-2 -right-2 w-8 h-8 bg-white rounded-xl flex items-center justify-center shadow-lg hover:scale-110 transition-all">
                <Edit3 className="w-3.5 h-3.5 text-teal-600" />
