                      <p className={`text-lg font-black ${s.text}`}>{s.value}</p>
                    </div>
                  ))}
                </div>
              </div>

              {/* Quick actions */}
              <div className="bg-white rounded-3xl border border-gray-100 shadow-sm p-6">
                <h3 className="font-black text-slate-900 mb-4">Quick Actions</h3>
                <div className="space-y-2">
                  {[
                    { label: 'Continue Shopping', page: 'products', cls: PRI,                                 Icon: ShoppingBag  },
                    { label: 'View All Orders',   page: 'orders',   cls: 'bg-gradient-to-r from-violet-500 to-purple-600 hover:from-violet-600 hover:to-purple-700 text-white font-semibold transition-all shadow-md hover:shadow-purple-200/50 active:scale-95', Icon: Package },
                    { label: 'View Cart',         page: 'cart',     cls: 'bg-gradient-to-r from-emerald-500 to-green-600 hover:from-emerald-600 hover:to-green-700 text-white font-semibold transition-all shadow-md hover:shadow-green-200/50 active:scale-95', Icon: ShoppingCart },
                  ].map((a, i) => (
                    <button key={i} onClick={() => setCurrentPage(a.page)}
                      className={`w-full flex items-center justify-between px-4 py-3 rounded-2xl text-sm ${a.cls}`}>
                      <div className="flex items-center gap-2"><a.Icon className="w-4 h-4" />{a.label}</div>
                      <ArrowRight className="w-4 h-4" />
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* ════════════════════════════════════════════════════════
            TAB: Addresses
        ════════════════════════════════════════════════════════ */}
        {activeTab === 'addresses' && (
          <div style={{ animation: 'fadeIn .4s ease both' }}>
            <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden">
              {/* Header */}
              <div className="px-8 py-5 border-b border-gray-50 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-2xl flex items-center justify-center bg-gradient-to-br from-violet-500 to-purple-600">
                    <MapPin className="w-5 h-5 text-white" />
                  </div>
                  <div>
                    <h2 className="font-black text-slate-900">Saved Addresses</h2>
                    <p className="text-xs text-slate-400 font-medium">{profileData.addresses?.length || 0} addresses saved</p>
                  </div>
                </div>
                <div className="flex gap-2">
                  <button onClick={() => setAddressModal({ mode: 'add' })}
                    className={`${PRI} flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm`}>
                    <Plus className="w-4 h-4" /> Add Address
                  </button>
                  {profileData.addresses?.length > 0 && (
                    <button
                      onClick={async () => {
                        try {
                          for (const a of profileData.addresses) await addressAPI.remove(a.id);
                          await fetchAddresses();
                        } catch { setError('Failed to delete addresses'); }
                      }}
                      className="flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm font-bold text-red-500 bg-red-50 hover:bg-red-100 border border-red-100 transition-all active:scale-95">
                      <Trash2 className="w-4 h-4" /> Clear All
                    </button>
                  )}
                </div>
              </div>

              {/* Body */}
              <div className="p-8">
                {!profileData.addresses?.length ? (
                  /* Empty state */
                  <div className="text-center py-16">
                    <div className="w-20 h-20 bg-teal-50 rounded-3xl flex items-center justify-center mx-auto mb-4">
                      <MapPin className="w-9 h-9 text-teal-300" />
                    </div>
                    <h3 className="text-lg font-black text-slate-900 mb-2">No addresses yet</h3>
                    <p className="text-slate-500 text-sm mb-6">Add your first delivery address</p>
                    <button onClick={() => setAddressModal({ mode: 'add' })}
                      className={`${PRI} px-6 py-2.5 rounded-xl text-sm`}>
                      <Plus className="w-4 h-4 inline mr-1" /> Add Address
                    </button>
                  </div>
                ) : (
                  /* Address grid */
                  <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-4">
                    {profileData.addresses.map((addr, idx) => {
                      const meta = labelMeta[addr.label] || labelMeta.Other;
                      const Icon = meta.Icon;
                      return (
                        <div key={addr.id}
                          className="relative p-5 rounded-2xl border-2 transition-all hover:shadow-lg hover:shadow-teal-50 group"
                          style={{
                            borderColor:  addr.IsDefault ? 'rgba(20,184,166,0.4)' : '#f1f5f9',
                            background:   addr.IsDefault ? 'linear-gradient(135deg,#f0fdfa,#ecfeff)' : 'white',
                          }}>

                          {/* Default badge */}
                          {addr.IsDefault && (
                            <span className="absolute top-3 right-3 text-[10px] font-black text-teal-700 bg-teal-100 px-2.5 py-1 rounded-full border border-teal-200">
                              ⭐ Default
                            </span>
                          )}

                          {/* Hover action buttons */}
                          <div className="absolute top-3 right-3 flex gap-1 opacity-0 group-hover:opacity-100 transition-all">
                            {/* Edit button */}
                            <button
                              onClick={() => setAddressModal({ mode: 'edit', address: addr })}
                              className="w-7 h-7 flex items-center justify-center rounded-xl bg-teal-50 text-teal-500 hover:bg-teal-100 hover:text-teal-700 transition-all"
                              title="Edit address">
                              <Pencil className="w-3.5 h-3.5" />
                            </button>
                            {/* Delete button */}
                            <button
                              onClick={() => removeAddress(addr.id)}
                              className="w-7 h-7 flex items-center justify-center rounded-xl bg-red-50 text-red-400 hover:bg-red-100 hover:text-red-600 transition-all"
                              title="Delete address">
                              <Trash2 className="w-3.5 h-3.5" />
                            </button>
                          </div>

                          {/* Label icon */}
                          <div className={`w-10 h-10 rounded-2xl flex items-center justify-center mb-3 bg-gradient-to-br ${meta.bg}`}>
                            <Icon className="w-5 h-5 text-white" />
                          </div>

                          <p className="font-black text-slate-900 mb-1 pr-16">
                            {addr.label || `Address ${idx + 1}`}
                          </p>
                          <p className="text-sm text-slate-500 leading-relaxed">
                            {[addr.AddressLine1, addr.AddressLine2, addr.City, addr.State, addr.PostalCode, addr.Country]
                              .filter(Boolean).join(', ')}
                          </p>
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {/* ════════════════════════════════════════════════════════
            TAB: Orders
        ════════════════════════════════════════════════════════ */}
        {activeTab === 'orders' && (
          <div style={{ animation: 'fadeIn .4s ease both' }}>
            <div className="bg-white rounded-3xl border border-gray-100 shadow-sm overflow-hidden">
              <div className="px-8 py-5 border-b border-gray-50 flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 rounded-2xl flex items-center justify-center bg-gradient-to-br from-orange-400 to-rose-500">
                    <Package className="w-5 h-5 text-white" />
                  </div>
                  <div>
                    <h2 className="font-black text-slate-900">Order History</h2>
                    <p className="text-xs text-slate-400 font-medium">{orders.length} orders placed</p>
                  </div>
                </div>
                <button onClick={() => setCurrentPage('orders')}
                  className={`${PRI} flex items-center gap-1.5 px-4 py-2 rounded-xl text-sm`}>
                  View All <ArrowRight className="w-4 h-4" />
                </button>
              </div>

              <div className="p-8">
                {orders.length === 0 ? (
                  <div className="text-center py-16">
                    <div className="w-20 h-20 bg-teal-50 rounded-3xl flex items-center justify-center mx-auto mb-4">
                      <Package className="w-9 h-9 text-teal-300" />
                    </div>
                    <h3 className="text-lg font-black text-slate-900 mb-2">No orders yet</h3>
                    <p className="text-slate-500 text-sm mb-6">Start shopping to see your orders here</p>
                    <button onClick={() => setCurrentPage('products')}
                      className={`${PRI} px-6 py-2.5 rounded-xl text-sm`}>
                      Shop Now →
                    </button>
                  </div>
                ) : (
                  <div className="space-y-3">
                    {orders.slice(0, 10).map(order => {
                      const statusCls = {
                        Pending:    'bg-yellow-50 text-yellow-700 border-yellow-200',
                        Processing: 'bg-blue-50 text-blue-700 border-blue-200',
                        Shipped:    'bg-violet-50 text-violet-700 border-violet-200',
                        Delivered:  'bg-emerald-50 text-emerald-700 border-emerald-200',
                        Cancelled:  'bg-red-50 text-red-700 border-red-200',
                      }[order.status] || 'bg-slate-50 text-slate-700 border-slate-200';

                      return (
                        <div key={order.id}
                          className="flex items-center gap-4 p-5 rounded-2xl border border-gray-100 hover:border-teal-200 hover:shadow-md hover:shadow-teal-50 transition-all group cursor-pointer"
                          onClick={() => setCurrentPage('orders')}>
                          <div className="w-12 h-12 rounded-2xl flex items-center justify-center text-sm font-black text-teal-700 bg-gradient-to-br from-teal-50 to-cyan-50 border border-teal-100 shrink-0">
                            #{order.id % 100}
                          </div>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 mb-0.5">
                              <p className="font-black text-slate-900 text-sm">Order #{order.id}</p>
                              <span className={`text-[10px] font-bold px-2 py-0.5 rounded-full border ${statusCls}`}>
                                {order.status || 'Processing'}
                              </span>
                            </div>
                            <p className="text-xs text-slate-400 font-medium">
                              {order.orderDate
                                ? new Date(order.orderDate).toLocaleDateString('en-IN', { year: 'numeric', month: 'short', day: 'numeric' })
                                : 'N/A'}
                            </p>
                          </div>
                          <p className="font-black text-teal-600 shrink-0">₹{(order.totalAmount || 0).toLocaleString()}</p>
                          <ChevronRight className="w-4 h-4 text-slate-300 group-hover:text-teal-500 group-hover:translate-x-1 transition-all" />
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      {/* ── Toast notification ──────────────────────────────────── */}
      {toast && (
        <div
          className={`fixed bottom-6 left-1/2 -translate-x-1/2 z-[200] flex items-center gap-3 px-5 py-3.5 rounded-2xl shadow-2xl text-sm font-bold text-white`}
          style={{
            animation: 'toastIn .3s cubic-bezier(0.34,1.56,0.64,1) both',
            background: toast.type === 'success'
              ? 'linear-gradient(135deg,#14b8a6,#0891b2)'
              : 'linear-gradient(135deg,#ef4444,#dc2626)',
            boxShadow: toast.type === 'success'
              ? '0 8px 32px rgba(20,184,166,0.4)'
              : '0 8px 32px rgba(239,68,68,0.4)',
          }}>
          <span className="text-base">{toast.type === 'success' ? '✅' : '❌'}</span>
          {toast.msg}
        </div>
      )}

      {/* ── Address Modal (Add / Edit) ─────────────────────────── */}
      {addressModal && (
        <AddressModal
          mode={addressModal.mode}
          existingAddress={addressModal.address || null}
          onClose={() => setAddressModal(null)}
          onSave={handleSaveAddress}
          saving={savingAddress}
        />
      )}

      {/* ── Footer ───────────────────────────────────────────────── */}
      <footer className="bg-white border-t border-gray-100 py-8 mt-8">
        <div className="max-w-7xl mx-auto px-6 flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-2">
            <div className="bg-gradient-to-br from-teal-500 to-cyan-600 p-1.5 rounded-lg">
              <ShoppingBag className="w-4 h-4 text-white" />
            </div>
            <span className="text-lg font-black text-slate-900 tracking-tight">ShopAI</span>
          </div>
          <p className="text-slate-400 text-sm font-medium">© {new Date().getFullYear()} — Designed for the future of commerce.</p>
          <div className="flex gap-6">
            {['Help', 'Privacy', 'Terms'].map(l => (
              <button key={l} className="text-sm font-bold text-slate-500 hover:text-teal-600 transition-colors">{l}</button>
            ))}
          </div>
        </div>
      </footer>
    </div>
  );
};

export default ProfilePage;
